import React from 'react';
import { Calendar, Gauge, CheckCircle2, ShoppingCart, Trash2, Edit, Tag } from 'lucide-react';
import { Motorcycle } from '../types';

interface MotorCardProps {
  motor: Motorcycle;
  isAdminView?: boolean;
  onDelete?: (id: string) => void;
  onEdit?: (motor: Motorcycle) => void;
  onUpdateStatus?: (id: string, status: 'Tersedia' | 'Terjual') => void;
}

const MotorCard: React.FC<MotorCardProps> = ({ 
  motor, 
  isAdminView = false, 
  onDelete, 
  onEdit,
  onUpdateStatus 
}) => {
  const formatPrice = (price: number) => {
    return new Intl.NumberFormat('id-ID', {
      style: 'currency',
      currency: 'IDR',
      minimumFractionDigits: 0,
    }).format(price);
  };

  return (
    <div className="bg-white rounded-2xl overflow-hidden border border-slate-200 shadow-sm hover:shadow-xl transition-all duration-300 flex flex-col group">
      <div className="relative h-56 overflow-hidden">
        <img 
          src={motor.imageUrl} 
          alt={`${motor.brand} ${motor.model}`}
          className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
        />
        <div className="absolute top-4 left-4 flex flex-col gap-2">
           <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider shadow-sm ${
            motor.status === 'Tersedia' ? 'bg-green-500 text-white' : 'bg-slate-700 text-white'
          }`}>
            {motor.status}
          </span>
          <span className="bg-white/90 backdrop-blur px-3 py-1 rounded-full text-xs font-bold text-slate-800 uppercase tracking-wider shadow-sm border border-slate-200">
            {motor.condition}
          </span>
        </div>
        {isAdminView && (
          <div className="absolute top-4 right-4 flex gap-2">
            <button 
              onClick={() => onEdit?.(motor)}
              className="p-2 bg-blue-600 text-white rounded-full hover:bg-blue-700 shadow-lg transition-colors"
            >
              <Edit size={16} />
            </button>
            <button 
              onClick={() => onDelete?.(motor.id)}
              className="p-2 bg-red-600 text-white rounded-full hover:bg-red-700 shadow-lg transition-colors"
            >
              <Trash2 size={16} />
            </button>
          </div>
        )}
      </div>

      <div className="p-5 flex-1 flex flex-col">
        <div className="mb-4">
          <h3 className="text-xl font-bold text-slate-900 leading-tight mb-1 truncate">
            {motor.brand} {motor.model}
          </h3>
          <p className="text-2xl font-black text-red-600 tracking-tight">
            {formatPrice(motor.price)}
          </p>
        </div>

        <div className="grid grid-cols-2 gap-3 mb-4">
          <div className="flex items-center text-slate-500 text-sm">
            <Calendar size={14} className="mr-2 text-slate-400" />
            <span>Tahun {motor.year}</span>
          </div>
          <div className="flex items-center text-slate-500 text-sm">
            <Gauge size={14} className="mr-2 text-slate-400" />
            <span>KM: {motor.mileage}</span>
          </div>
        </div>

        <p className="text-slate-600 text-sm line-clamp-3 mb-6 leading-relaxed flex-1">
          {motor.description}
        </p>

        {isAdminView ? (
           <div className="flex gap-2">
             <button
                onClick={() => onUpdateStatus?.(motor.id, motor.status === 'Tersedia' ? 'Terjual' : 'Tersedia')}
                className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-all text-sm ${
                  motor.status === 'Tersedia' 
                    ? 'bg-slate-800 text-white hover:bg-black' 
                    : 'bg-green-600 text-white hover:bg-green-700'
                }`}
              >
                <Tag size={18} />
                {motor.status === 'Tersedia' ? 'Set Terjual' : 'Set Tersedia'}
              </button>
           </div>
        ) : (
          <button 
            disabled={motor.status === 'Terjual'}
            className={`w-full flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-all ${
              motor.status === 'Tersedia' 
                ? 'bg-red-600 text-white hover:bg-red-700 shadow-lg shadow-red-200' 
                : 'bg-slate-200 text-slate-400 cursor-not-allowed'
            }`}
          >
            <ShoppingCart size={20} />
            {motor.status === 'Tersedia' ? 'Hubungi Penjual' : 'Sudah Terjual'}
          </button>
        )}
      </div>
    </div>
  );
};

export default MotorCard;

import React, { useState } from 'react';
import { PlusCircle, Sparkles, X, Save, Image as ImageIcon, Search } from 'lucide-react';
import { Motorcycle } from '../types';
import { generateMotorDescription } from '../services/geminiService';
import MotorCard from './MotorCard';

interface AdminPanelProps {
  motors: Motorcycle[];
  onAddMotor: (motor: Omit<Motorcycle, 'id' | 'createdAt'>) => void;
  onUpdateMotor: (motor: Motorcycle) => void;
  onDeleteMotor: (id: string) => void;
  onUpdateStatus: (id: string, status: 'Tersedia' | 'Terjual') => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  motors, 
  onAddMotor, 
  onUpdateMotor, 
  onDeleteMotor,
  onUpdateStatus 
}) => {
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingMotor, setEditingMotor] = useState<Motorcycle | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const [formData, setFormData] = useState({
    brand: '',
    model: '',
    year: new Date().getFullYear(),
    price: 0,
    mileage: '',
    condition: 'Mulus' as Motorcycle['condition'],
    imageUrl: '',
    description: '',
    status: 'Tersedia' as Motorcycle['status']
  });

  const handleOpenForm = (motor?: Motorcycle) => {
    if (motor) {
      setEditingMotor(motor);
      setFormData({
        brand: motor.brand,
        model: motor.model,
        year: motor.year,
        price: motor.price,
        mileage: motor.mileage,
        condition: motor.condition,
        imageUrl: motor.imageUrl,
        description: motor.description,
        status: motor.status
      });
    } else {
      setEditingMotor(null);
      setFormData({
        brand: '',
        model: '',
        year: new Date().getFullYear(),
        price: 0,
        mileage: '',
        condition: 'Mulus',
        imageUrl: '',
        description: '',
        status: 'Tersedia'
      });
    }
    setIsFormOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingMotor) {
      onUpdateMotor({ ...editingMotor, ...formData });
    } else {
      onAddMotor(formData);
    }
    setIsFormOpen(false);
  };

  const handleAutoDescription = async () => {
    if (!formData.brand || !formData.model) {
      alert("Masukkan merek dan tipe motor terlebih dahulu!");
      return;
    }
    setIsGenerating(true);
    const desc = await generateMotorDescription(
      formData.brand, 
      formData.model, 
      formData.year, 
      formData.condition
    );
    setFormData(prev => ({ ...prev, description: desc }));
    setIsGenerating(false);
  };

  const filteredMotors = motors.filter(m => 
    `${m.brand} ${m.model}`.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
        <div>
          <h2 className="text-3xl font-black text-slate-900 tracking-tight">Manajemen Inventaris</h2>
          <p className="text-slate-500">Kelola stok motor di Jawa Motor Palu</p>
        </div>

        <div className="flex flex-col sm:flex-row gap-4">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Cari motor..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="pl-10 pr-4 py-2 border border-slate-200 rounded-xl focus:ring-2 focus:ring-red-500 focus:outline-none w-full sm:w-64"
            />
          </div>
          <button 
            onClick={() => handleOpenForm()}
            className="flex items-center justify-center gap-2 bg-red-600 text-white px-6 py-3 rounded-xl font-bold hover:bg-red-700 transition-all shadow-lg shadow-red-200"
          >
            <PlusCircle size={20} />
            Tambah Motor Baru
          </button>
        </div>
      </div>

      {filteredMotors.length === 0 ? (
        <div className="bg-white rounded-3xl p-12 border-2 border-dashed border-slate-200 text-center">
          <div className="bg-slate-100 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
            <ImageIcon className="text-slate-400" size={32} />
          </div>
          <h3 className="text-xl font-bold text-slate-900 mb-2">Belum ada data motor</h3>
          <p className="text-slate-500 mb-6">Mulai tambahkan koleksi motor bekas Anda hari ini.</p>
          <button 
            onClick={() => handleOpenForm()}
            className="text-red-600 font-bold hover:underline"
          >
            Tambah motor pertama
          </button>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
          {filteredMotors.map(motor => (
            <MotorCard 
              key={motor.id} 
              motor={motor} 
              isAdminView 
              onDelete={onDeleteMotor}
              onEdit={handleOpenForm}
              onUpdateStatus={onUpdateStatus}
            />
          ))}
        </div>
      )}

      {/* Modal Form */}
      {isFormOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm overflow-y-auto">
          <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
            <div className="px-8 py-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <h3 className="text-2xl font-black text-slate-900">
                {editingMotor ? 'Edit Motor' : 'Tambah Unit Baru'}
              </h3>
              <button 
                onClick={() => setIsFormOpen(false)}
                className="p-2 hover:bg-slate-200 rounded-full transition-colors"
              >
                <X size={24} className="text-slate-500" />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-2">Merek (Contoh: Honda)</label>
                  <input 
                    required
                    type="text" 
                    value={formData.brand}
                    onChange={e => setFormData({...formData, brand: e.target.value})}
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-red-500 focus:outline-none bg-slate-50"
                  />
                </div>
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-2">Model/Tipe (Contoh: Vario 150)</label>
                  <input 
                    required
                    type="text" 
                    value={formData.model}
                    onChange={e => setFormData({...formData, model: e.target.value})}
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-red-500 focus:outline-none bg-slate-50"
                  />
                </div>
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-2">Tahun</label>
                  <input 
                    required
                    type="number" 
                    value={formData.year}
                    onChange={e => setFormData({...formData, year: parseInt(e.target.value)})}
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-red-500 focus:outline-none bg-slate-50"
                  />
                </div>
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-2">Kilometer (KM)</label>
                  <input 
                    required
                    type="text" 
                    placeholder="Contoh: 15rb - 20rb"
                    value={formData.mileage}
                    onChange={e => setFormData({...formData, mileage: e.target.value})}
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-red-500 focus:outline-none bg-slate-50"
                  />
                </div>
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-2">Harga (Rp)</label>
                  <input 
                    required
                    type="number" 
                    value={formData.price}
                    onChange={e => setFormData({...formData, price: parseInt(e.target.value)})}
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-red-500 focus:outline-none bg-slate-50"
                  />
                </div>
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-2">Kondisi</label>
                  <select 
                    value={formData.condition}
                    onChange={e => setFormData({...formData, condition: e.target.value as any})}
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-red-500 focus:outline-none bg-slate-50"
                  >
                    <option value="Mulus">Mulus (Like New)</option>
                    <option value="Standar">Standar Pemakaian</option>
                    <option value="Modifikasi">Modifikasi</option>
                  </select>
                </div>
              </div>

              <div>
                <label className="block text-sm font-bold text-slate-700 mb-2">URL Foto Produk</label>
                <div className="flex gap-2">
                  <input 
                    required
                    type="text" 
                    placeholder="https://images.unsplash.com/..."
                    value={formData.imageUrl}
                    onChange={e => setFormData({...formData, imageUrl: e.target.value})}
                    className="flex-1 px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-red-500 focus:outline-none bg-slate-50"
                  />
                </div>
                <p className="mt-2 text-xs text-slate-400">Gunakan link gambar dari internet (Unsplash/Imgur/dsb).</p>
              </div>

              <div>
                <div className="flex justify-between items-center mb-2">
                  <label className="block text-sm font-bold text-slate-700">Deskripsi Promosi</label>
                  <button 
                    type="button"
                    onClick={handleAutoDescription}
                    disabled={isGenerating}
                    className="text-xs flex items-center gap-1 text-purple-600 font-bold hover:text-purple-700 disabled:opacity-50"
                  >
                    <Sparkles size={14} />
                    {isGenerating ? 'Menulis...' : 'Tulis Otomatis dengan AI'}
                  </button>
                </div>
                <textarea 
                  required
                  rows={4}
                  value={formData.description}
                  onChange={e => setFormData({...formData, description: e.target.value})}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-red-500 focus:outline-none bg-slate-50"
                ></textarea>
              </div>

              <div className="flex gap-4 pt-4">
                <button 
                  type="button"
                  onClick={() => setIsFormOpen(false)}
                  className="flex-1 py-4 border border-slate-200 rounded-xl font-bold text-slate-600 hover:bg-slate-50 transition-colors"
                >
                  Batal
                </button>
                <button 
                  type="submit"
                  className="flex-1 py-4 bg-red-600 text-white rounded-xl font-bold hover:bg-red-700 shadow-xl shadow-red-200 transition-all flex items-center justify-center gap-2"
                >
                  <Save size={20} />
                  Simpan Unit
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

import React, { useState } from 'react';
import { Search, Filter, SlidersHorizontal, ChevronRight } from 'lucide-react';
