          <span className="inline-block px-4 py-1 rounded-full bg-red-600 text-white text-xs font-black uppercase tracking-[0.2em] mb-4">
            Showroom Terbesar di Palu
          </span>
          <h2 className="text-4xl md:text-6xl font-black text-white leading-[1.1] mb-6 tracking-tight">
            Cari Motor Bekas <br/><span className="text-red-600">Terpercaya</span> di Sini.
          </h2>
          <p className="text-lg text-slate-300 mb-8 max-w-lg leading-relaxed">
            Temukan unit impian Anda dengan kondisi terbaik, harga bersaing, dan proses cepat hanya di Jawa Motor Palu.
          </p>
          <div className="flex flex-wrap gap-4">
            <button className="bg-red-600 text-white px-8 py-4 rounded-xl font-bold hover:bg-red-700 transition-all shadow-lg shadow-red-600/20 flex items-center group">
              Lihat Unit Tersedia
              <ChevronRight size={20} className="ml-2 group-hover:translate-x-1 transition-transform" />
            </button>
            <button className="bg-white/10 backdrop-blur text-white px-8 py-4 rounded-xl font-bold hover:bg-white/20 transition-all">
              Hubungi Kami
