              className={`px-6 py-3 rounded-xl text-sm font-bold transition-all whitespace-nowrap ${
                brandFilter === brand 
                  ? 'bg-red-600 text-white shadow-md' 
                  : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
              }`}
            >
              {brand}
            </button>
          ))}
        </div>
      </div>

      {/* Catalog Grid */}
      <div className="mb-12">
        <div className="flex items-center justify-between mb-8">
           <h3 className="text-2xl font-bold text-slate-900 flex items-center">
             Katalog Terbaru
             <span className="ml-3 px-3 py-1 bg-slate-100 rounded-full text-xs font-bold text-slate-500">{filteredMotors.length} Unit</span>
           </h3>
           <button className="flex items-center text-slate-500 hover:text-red-600 font-bold text-sm">
             <SlidersHorizontal size={16} className="mr-2" />
             Urutkan
           </button>
        </div>

        {filteredMotors.length === 0 ? (
          <div className="text-center py-24 bg-white rounded-3xl border border-slate-100 shadow-sm">
            <div className="bg-slate-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6">
              <Search size={40} className="text-slate-300" />
            </div>
            <h4 className="text-2xl font-bold text-slate-900 mb-2">Motor tidak ditemukan</h4>
            <p className="text-slate-500">Coba gunakan kata kunci lain atau ubah filter pencarian Anda.</p>
            <button 
              onClick={() => {setSearchTerm(''); setBrandFilter('Semua');}}
              className="mt-6 text-red-600 font-bold hover:underline"
            >
              Reset Pencarian
            </button>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
            {filteredMotors.map(motor => (
              <MotorCard key={motor.id} motor={motor} />
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default Catalog;

