const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('visitor');
  const [isAdmin, setIsAdmin] = useState(false);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [motors, setMotors] = useState<Motorcycle[]>(() => {
    const saved = localStorage.getItem('jmp_inventory');
    return saved ? JSON.parse(saved) : INITIAL_MOTORS;
  });

  useEffect(() => {
    localStorage.setItem('jmp_inventory', JSON.stringify(motors));
  }, [motors]);

  const handleToggleView = (newView: ViewType) => {
    if (newView === 'admin' && !isAdmin) {
      setShowLoginModal(true);
      return;
    }
    setView(newView);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    // Simple mock login for demo
    setIsAdmin(true);
    setShowLoginModal(false);
    setView('admin');
  };

  const handleLogout = () => {
    setIsAdmin(false);
    setView('visitor');
  };

  const addMotor = (motorData: Omit<Motorcycle, 'id' | 'createdAt'>) => {
    const newMotor: Motorcycle = {
      ...motorData,
      id: Math.random().toString(36).substr(2, 9),
      createdAt: Date.now(),
    };
    setMotors([newMotor, ...motors]);
  };

  const updateMotor = (updatedMotor: Motorcycle) => {
    setMotors(motors.map(m => m.id === updatedMotor.id ? updatedMotor : m));
  };

  const deleteMotor = (id: string) => {
    if (confirm('Apakah Anda yakin ingin menghapus unit ini dari katalog?')) {
      setMotors(motors.filter(m => m.id !== id));
    }
  };

  const updateStatus = (id: string, status: 'Tersedia' | 'Terjual') => {
    setMotors(motors.map(m => m.id === id ? { ...m, status } : m));
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar 
        currentView={view} 
        onToggleView={handleToggleView} 
        isAdmin={isAdmin}
        onLogout={handleLogout}
      />

      <main className="flex-1 bg-slate-50">
        {view === 'visitor' ? (
          <Catalog motors={motors} />
        ) : (
          <AdminPanel 
            motors={motors} 
            onAddMotor={addMotor} 
            onUpdateMotor={updateMotor}
            onDeleteMotor={deleteMotor}
            onUpdateStatus={updateStatus}
          />
        )}
      </main>

      <Footer />

      {/* Login Modal */}
      {showLoginModal && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white w-full max-w-md rounded-3xl shadow-2xl p-8 relative animate-in fade-in slide-in-from-bottom-4 duration-300">
             <button 
                onClick={() => setShowLoginModal(false)}
                className="absolute top-4 right-4 p-2 hover:bg-slate-100 rounded-full transition-colors"
              >
                <X size={20} className="text-slate-400" />
              </button>

            <div className="text-center mb-8">
              <div className="bg-red-600 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-xl shadow-red-200">
                <Key className="text-white" size={32} />
              </div>
              <h2 className="text-2xl font-black text-slate-900">Admin Login</h2>
              <p className="text-slate-500">Akses khusus pengelola Jawa Motor Palu</p>
            </div>

            <form onSubmit={handleLogin} className="space-y-6">
              <div>
                <label className="block text-sm font-bold text-slate-700 mb-2">Username</label>
                <input 
                  type="text" 
                  defaultValue="admin"
                  required
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-red-500 focus:outline-none bg-slate-50" 
                />
              </div>
              <div>
                <label className="block text-sm font-bold text-slate-700 mb-2">Password</label>
                <input 
                  type="password" 
                  defaultValue="123456"
                  required
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-red-500 focus:outline-none bg-slate-50" 
                />
              </div>
              <button 
                type="submit"
                className="w-full py-4 bg-slate-900 text-white rounded-xl font-bold hover:bg-black transition-all flex items-center justify-center gap-2 shadow-lg"
              >
                <LogIn size={20} />
                Masuk Sekarang
              </button>
            </form>
            <p className="mt-6 text-center text-xs text-slate-400">
              Demo: Klik 'Masuk Sekarang' untuk akses (Password apa saja).
            </p>
          </div>
        </div>
      )}
    </div>
  );
};

